"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[5015],{89311:e=>{e.exports=JSON.parse('{"functions":[{"name":"logon","desc":"Joins the shared Interposer medium and returns an [InterposerApi] for\\ntracking peers and registering protocols.","params":[{"name":"devEnvName","desc":"Identifier passed to [IsLocalDev] and used as the log prefix; lets plugins stand up isolated dev/prod instances.","lua_type":"string"},{"name":"mediumName","desc":"Name of the `BindableEvent` parented under `StudioService` that peers communicate through. Plugins sharing a name see each other; plugins on different names form isolated channels.","lua_type":"string"},{"name":"scope","desc":"Cleanup scope; teardown functions and connections are appended here.","lua_type":"{ unknown }"}],"returns":[{"desc":"","lua_type":"InterposerApi"}],"function_type":"static","source":{"line":84,"path":"plugin/interposer/init.luau"}}],"properties":[],"types":[],"name":"Interposer","desc":"Cross-plugin RPC layer for Roblox Studio. A `BindableEvent` parented\\nto `StudioService` acts as the public medium that every cooperating\\nplugin shares. Each plugin calls [Interposer.logon] to join the\\nmedium, discover other peers, and register typed protocols.\\n\\nSlight deviation from the upstream: the dev-env name (used by\\n[IsLocalDev] and the [ElttobLog] logger prefix) is a parameter rather\\nthan the hardcoded `\\"Suite\\"`, so plugins can stand up their own\\nInterposer instances without colliding on log output.","source":{"line":17,"path":"plugin/interposer/init.luau"}}')}}]);